// v5
function getProjectName(ru) {
  return LANG.current === 'en' ? (PROJ_EN[ru] || ru) : ru;
}

// ── TRANSLATIONS ──
const LANG = { current: 'en' };

function setLang(lang) {
  LANG.current = lang;
  document.getElementById('html-root').lang = lang;
  document.querySelectorAll('.lang-btn').forEach(b => b.classList.toggle('active', b.textContent === lang.toUpperCase()));

  // Update all data-ru / data-en elements
  document.querySelectorAll('[data-ru]').forEach(el => {
    const val = el.getAttribute('data-' + lang);
    if (!val) return;
    if (el.tagName === 'INPUT') {
      el.placeholder = el.getAttribute('data-' + lang + '-placeholder') || val;
    } else if (val.includes('<')) {
      el.innerHTML = val;
    } else {
      el.textContent = val;
    }
  });

  // Logo
  const lm = document.getElementById('logo-main');
  if (lm) lm.innerHTML = lang === 'ru' ? 'ПЯТЫЙ <span>РАДИУС</span>' : 'FIFTH <span>RADIUS</span>';

  // Hero title
  const ht = document.getElementById('hero-title-el');
  if (ht) ht.innerHTML = lang === 'ru' ? 'Пятый<br><em>Радиус</em>' : 'Fifth<br><em>Radius</em>';

  // Title
  document.title = lang === 'ru' ? 'Пятый Радиус — Архитектурное бюро' : 'Fifth Radius — Architecture Bureau';

  // Special: search placeholder
  const si = document.getElementById('searchInput');
  if (si) si.placeholder = lang === 'ru' ? 'Поиск по проекту...' : 'Search project...';

  renderGrid(getFiltered());
}

